module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output reg wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

    reg [WIDTH-1:0] ram [DEPTH-1:0];
    reg [ADDR_WIDTH-1:0] waddr, raddr;
    reg wenc, renc;
    always @(posedge wclk) begin
        if (wenc) begin
            ram[waddr] <= wdata;
        end
    end
    always @(posedge rclk) begin
        rdata <= ram[raddr];
    end

    reg [ADDR_WIDTH:0] wp;
    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wp <= 0;
        end else if (winc && !wfull) begin
            wp <= wp + 1;
        end
    end

    reg [ADDR_WIDTH:0] rp;
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rp <= 0;
        end else if (rinc && !rempty) begin
            rp <= rp + 1;
        end
    end

    reg [ADDR_WIDTH:0] rps1, rps2;
    always @(posedge wclk) begin
        rps1 <= rp;
        rps2 <= rps1;
    end

    reg [ADDR_WIDTH:0] wps1, wps2;
    always @(posedge rclk) begin
        wps1 <= wp;
        wps2 <= wps1;
    end

    assign rempty = (rps2 == wp);
    always @(posedge wclk) begin
        wfull <= (wps2 == {~rps1[ADDR_WIDTH], rps1[ADDR_WIDTH-1:0]});
    end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
